const items = $input.all();

if (items.length < 2) {
  throw new Error("Esperava pelo menos 2 registros (semana atual e semana anterior).");
}

const atual = items[0].json;
const anterior = items[1].json;

function variacao(atual, anterior) {
  atual = Number(atual);
  anterior = Number(anterior);

  if (!isFinite(atual) || !isFinite(anterior)) return null;
  if (anterior === 0) return null;

  return ((atual - anterior) / anterior) * 100;
}

function direcao(atual, anterior, menorMelhor = false, tolerancia = 0) {
  atual = Number(atual);
  anterior = Number(anterior);

  const diferenca = atual - anterior;

  if (Math.abs(diferenca) <= tolerancia) {
    return "➖";
  }

  if (menorMelhor) {
    return diferenca < 0 ? "🟢" : "🔴";
  }

  return diferenca > 0 ? "🟢" : "🔴";
}

return [
  {
    json: {
      atual,
      anterior,

      comparativo: {
        cliques: {
          variacao: variacao(atual.cliques, anterior.cliques),
          icone: direcao(atual.cliques, anterior.cliques)
        },

        ctr: {
          variacao_pp: Number(atual.ctr) - Number(anterior.ctr),
          icone: direcao(atual.ctr, anterior.ctr, false, 0.5)
        },

        visitas_pagina: {
          variacao: variacao(atual.visitas_pagina, anterior.visitas_pagina),
          icone: direcao(atual.visitas_pagina, anterior.visitas_pagina)
        },

        connect_rate: {
          variacao_pp: Number(atual.connect_rate) - Number(anterior.connect_rate),
          icone: direcao(atual.connect_rate, anterior.connect_rate, false, 5)
        },

        conversao_pagina: {
          variacao_pp: Number(atual.conversao_pagina) - Number(anterior.conversao_pagina),
          icone: direcao(atual.conversao_pagina, anterior.conversao_pagina, false, 5)
        },

        conversao_checkout: {
          variacao_pp: Number(atual.conversao_checkout) - Number(anterior.conversao_checkout),
          icone: direcao(atual.conversao_checkout, anterior.conversao_checkout, false, 5)
        },

        vendas_trafego: {
          variacao: variacao(atual.vendas_trafego, anterior.vendas_trafego),
          icone: direcao(atual.vendas_trafego, anterior.vendas_trafego)
        },

        custo_por_compra: {
          variacao: variacao(atual.custo_por_compra, anterior.custo_por_compra),
          icone: direcao(
            variacao(atual.custo_por_compra, anterior.custo_por_compra),
            0,
            true,
            10
          )
        },

        roas: {
          variacao: variacao(atual.roas, anterior.roas),
          icone: direcao(
            variacao(atual.roas, anterior.roas),
            0,
            false,
            10
          )
        },

        investimento: {
          variacao: variacao(atual.investimento, anterior.investimento),
          icone: direcao(
            variacao(atual.investimento, anterior.investimento),
            0,
            false,
            10
          )
        },

        faturamento: {
          variacao: variacao(atual.faturamento, anterior.faturamento),
          icone: direcao(
            variacao(atual.faturamento, anterior.faturamento),
            0,
            false,
            10
          )
        }
      }
    }
  }
];

